def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    import re
    pres = Presentation(modified_ppt_path)
    slide = pres.slides[3]
    # Get all texts on original slide 4
    orig_pres = Presentation(original_ppt_path)
    orig_slide = orig_pres.slides[3]
    orig_texts = set(s.text.strip() for s in orig_slide.shapes if hasattr(s, 'text'))
    # Find new textbox
    for shape in slide.shapes:
        if shape.shape_type == 17 and shape.has_text_frame:
            txt = shape.text.strip()
            if txt and txt not in orig_texts:
                # Check if it contains the word 'prostomium' and some form of explanation
                # Look for a sentence or clause containing 'prostomium' and a definition-like structure
                if re.search(r'prostomium', txt, re.IGNORECASE):
                    # Must have more than just the word; should be a phrase/sentence
                    if len(txt.split()) > 2:
                        keywords = ["is", "means", "refers", "part", "region", "structure", "anterior", "front"]
                        if any(k in txt.lower() for k in keywords):
                            return "Text box contains an explanation of 'prostomium'.", 1.0
                elif len(txt) > 20:
                    # If explanation doesn't repeat the word but is clearly a definition
                    return "Text box contains a definition/explanation without repeating 'prostomium'.", 1.0
    return "No explanation of 'prostomium' found in added text box.", 0.0

